// Extract and validate trigger data
const triggerData = Object.assign({}, $json["body"] || {});

// Determine trigger type and extract relevant context
const triggerType = triggerData.type || "lead_created";
const entityId = triggerData.id || triggerData.customer_id || triggerData.property_id;

// Prepare context for subsequent steps
return [{
  json: {
    triggerType: triggerType,
    entityId: entityId,
    triggerData: triggerData,
    timestamp: new Date().toISOString(),
    workflowId: "comprehensive_crm_automation"
  }
}];

// Combine webhook data with database context
const dbResult = $json[0] || {};
const webhookData = $node["Extract Context"].json.triggerData;

// Build comprehensive context
const context = {
  ...webhookData,
  dbRecord: dbResult,
  contextTimestamp: new Date().toISOString(),
  dataSources: ["webhook", "database"]
};

return [{ json: context }];

// Prepare form data for external web form submission
const context = $json;

// Example: Prepare data for a property listing web form
const formData = {
  property_title: context.property_title || "",
  property_address: context.property_address || "",
  price: context.price || 0,
  bedrooms: context.bedrooms || 0,
  bathrooms: context.bathrooms || 0,
  square_feet: context.square_feet || 0,
  description: context.description || "",
  features: JSON.stringify(context.features || []),
  agent_id: context.agent_id || "",
  listing_date: context.listing_date || new Date().toISOString().split('T')[0]
};

return [{ json: { formData: formData, targetUrl: "https://example-realestate-site.com/submit-property" } }];

// Send notifications via multiple channels
const context = $json;
const notifications = [];

// Email notification
notifications.push({
  channel: "email",
  to: context.agent_email || "manager@company.com",
  subject: `Property Update: ${context.property_title || 'Property'}`,
  body: `\n\nProperty details:\n- Title: ${context.property_title}\n- Address: ${context.property_address}\n- Price: $${context.price}\n- Updated via CRM automation at ${new Date().toLocaleString()}\n\nView details: ${context.property_url || '#'}`
});

// SMS notification (if phone available)
if (context.agent_phone) {
  notifications.push({
    channel: "sms",
    to: context.agent_phone,
    message: `Property update: ${context.property_title} - $${context.price}. Check email for details.`
  });
}

// Slack notification
notifications.push({
  channel: "slack",
  channel: "#property-updates",
  message: `*Property Updated*: ${context.property_title}\n*Price*: $${context.price}\n*Agent*: ${context.agent_name || 'Unknown'}\n<${context.property_url || '#'}|View Property>`
});

return [{ json: { notifications: notifications } }];

// Send email notifications
const notifications = $json["notifications"] || [];
const emailNotifications = notifications.filter(n => n.channel === "email");

const emailPromises = emailNotifications.map(email => (
  fetch("http://host.docker.internal:5000/api/email/send", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      to: email.to,
      subject: email.subject,
      body: email.body,
      html: email.body.replace(/\\n/g, '<br>')
    })
  ))
));

return [{ json: { emailResults: await Promise.all(emailPromises) } }];

// Send SMS notifications
const notifications = $json["notifications"] || [];
const smsNotifications = notifications.filter(n => n.channel === "sms");

const smsPromises = smsNotifications.map(sms => (
  fetch("http://host.docker.internal:5000/api/sms/send", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      to: sms.to,
      message: sms.message
    })
  }))
));

return [{ json: { smsResults: await Promise.all(smsPromises) } }];

// Send Slack notifications
const notifications = $json["notifications"] || [];
const slackNotifications = notifications.filter(n => n.channel === "slack");

const slackPromises = slackNotifications.map(slack => (
  fetch("http://host.docker.internal:5000/api/slack/post", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      channel: slack.channel,
      message: slack.message
    })
  }))
));

return [{ json: { slackResults: await Promise.all(slackPromises) } }];

// Scrape website for additional property data (example)
const context = $json;

// Only run if we have a property URL to scrape
if (!context.property_url) {
  return [{ json: { scrapedData: null, skipped: true } }];
}

return [{ 
  json: { 
    scrapedData: {
      property_url: context.property_url,
      scrape_timestamp: new Date().toISOString(),
      notes: "Web scraping would happen here - in real implementation, use HTTP request or browser automation",
      status: "simulated"
    }
  } 
}];

// Final consolidation and logging
const context = $node["Combine Context"].json;
const formResult = $node["Submit Web Form"]?.json || {};
const emailResults = $node["Send Emails"]?.json?.emailResults || [];
const smsResults = $node["Send SMS"]?.json?.smsResults || [];
const slackResults = $node["Send Slack"]?.json?.slackResults || [];
const scrapedData = $node["Scrape Website Data"]?.json?.scrapedData || {};

const executionSummary = {
  workflowId: "comprehensive_crm_automation",
  executionId: crypto.randomUUID(),
  timestamp: new Date().toISOString(),
  triggerType: context.triggerType,
  entityId: context.entityId,
  actionsPerformed: {
    contextGathered: !!context.dbRecord,
    crmUpdated: true,
    webFormSubmitted: !!formResult.success,
    emailsSent: emailResults.length,
    smsSent: smsResults.length,
    slackNotifications: slackResults.length,
    websiteScraped: !!scrapedData.property_url
  },
  dataSources: [...(context.dataSources || []), "webform", "notification_services", "website_scraper"],
  status: "completed"
};

// Log execution to database for audit
return [{ json: { executionSummary: executionSummary } }];
